css:
.sheet-toolbar {
  position: relative;
  -webkit-app-region: drag;
  border-bottom: 1px solid #24273A;
}
.column-MessageListSidebar {
  border-left: transparent;
}
.flexbox-handle-horizontal div {
  height: 100%;
  box-shadow: transparent;
}
#inbox-html-wrapper > :not(table) a,
#inbox-plain-wrapper > :not(table) a,
#inbox-html-wrapper > :not(table) > :not(table) a,
#inbox-plain-wrapper > :not(table) > :not(table) a,
#inbox-html-wrapper > :not(table) > :not(table) > :not(table) a,
#inbox-plain-wrapper > :not(table) > :not(table) > :not(table) a,
#inbox-html-wrapper > :not(table) > :not(table) > :not(table) > :not(table) a,
#inbox-plain-wrapper > :not(table) > :not(table) > :not(table) > :not(table) a {
  color: #363A4F;
}
/* Badge with counter, secondary */
.item-count-box:not(.selected):not(.focused) {
  color: #24273A;
  box-shadow: 0 0.5px 0 #181825, 0 -0.5px 0 #181825, 0.5px 0 0 #181825, -0.5px 0 0 #181825;
  background: #B7BDF8;
}
/* Badge with counter, primary, selected */
.outline-view .item .item-count-box.alt-count {
  color: #B7BDF8;
  background: #24273A;
  box-shadow: none;
}
/* Badge with counter, primary, not selected */
.outline-view .item .item-count-box.alt-count:not(.selected):not(.focused) {
  color: #24273A;
  background: #B7BDF8;
  box-shadow: none;
}
/* tracking icon, unopened, unfocused */
.open-tracking-icon img.content-mask.unopened {
  background-color: #494D64;
}
/* tracking icon, mail list, unopened, focused */
.list-item.focused .open-tracking-icon img.content-mask.unopened,
.list-item.selected .open-tracking-icon img.content-mask.unopened {
  background-color: #494D64;
}
/* tracking icon, mail list, opened, unfocused */
.open-tracking-icon img.content-mask.opened {
  background-color: #CAD3F5;
}
/* tracking icon, opened, focused */
.list-item.focused .open-tracking-icon img.content-mask.opened,
.list-item.selected .open-tracking-icon img.content-mask.opened {
  background-color: #CAD3F5;
}
/* tracking icon, message list, focused, more than one selected */
.thread-list.handler-split .list-item.selected {
  color: #24273A;
}
/* tracking icon, message list, opened */
.open-tracking-message-status.opened img.content-mask {
  background-color: #CAD3F5;
}
/* tracking icon, mail list, unopened, unfocused */
.open-tracking-icon img.content-mask.unopened {
  background-color: #494D64;
}
.toolbar-activity .unread-count.active {
  background: #B7BDF8;
  color: #24273A;
}
.open-tracking-message-status.opened {
  color: #CAD3F5;
}
.open-tracking-message-status.unopened {
  color: #8087A2;
}
.account-switcher img {
  zoom: 1 !important;
  max-width: 10px;
  max-height: 6px;
  transform: none;
  background-image: none;
  background-color: #8087A2;
  -webkit-mask-repeat: no-repeat;
  -webkit-mask-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="10" height="6" viewBox="0 0 10 6"><path fill="#FFF" d="M0 0h1l4 4 4-4h1v1L5 6 0 1z"/></svg>');
}
.toolbar-activity .activity-toolbar-icon {
  background: #A5ADCB;
}
.div.suggestions:hover {
  color: #B7BDF8;
}
.button-dropdown.btn-emphasis .primary-item,
.button-dropdown.btn-emphasis .secondary-picker,
.button-dropdown.btn-emphasis .only-item {
  position: relative;
  color: #24273A;
  font-weight: 500;
  background: #B7BDF8;
  box-shadow: none;
  border: 0px solid #B7BDF8;
}
.button-dropdown.btn-emphasis .primary-item img.content-mask,
.button-dropdown.btn-emphasis .secondary-picker img.content-mask,
.button-dropdown.btn-emphasis .only-item img.content-mask {
  background-color: #24273A;
}
.button-dropdown.btn-emphasis .primary-item:active,
.button-dropdown.btn-emphasis .secondary-picker:active,
.button-dropdown.btn-emphasis .only-item:active {
  background: #B7BDF8;
}
.tokenizing-field .token {
  background: linear-gradient(to bottom, #363A4F 0%, #494D64 100%);
}
.tokenizing-field .token.selected,
.tokenizing-field .token.dragging {
  color: #24273A;
}
.tokenizing-field .token.selected .action img,
.tokenizing-field .token.dragging .action img {
  background-color: #24273A;
}
.menu .item.selected,
.menu .item:active {
  background-color: #4e4947;
  color: #CAD3F5;
}
.div.button-dropdown.open.open-down {
  background-color: #CAD3F5;
  color: #CAD3F5;
}
.menu .item.selected,
.menu .item:active {
  background-color: #B7BDF8;
  color: #24273A;
}
.menu .item.selected .primary,
.menu .item:active .primary {
  color: #24273A;
}
.menu .item.selected .secondary,
.menu .item:active .secondary {
  color: #363A4F;
}
.button-dropdown .primary-item,
.button-dropdown .only-item {
  background: -webkit-gradient(linear, left top, left bottom, from(#363A4F), to(#494D64));
}
.button-dropdown .secondary-picker {
  background: -webkit-gradient(linear, left top, left bottom, from(#363A4F), to(#494D64));
}
.button-dropdown.open.open-down .secondary-items {
  background: #363A4F;
}
#message-list .message-item-wrap .message-item-white-wrap.composer-outer-wrap {
  background: #363A4F;
}
#message-list .message-item-wrap .message-item-white-wrap.composer-outer-wrap.focused {
  box-shadow: 0 0 0.5px rgba(0, 0, 0, 0.28), 0 1px 1.5px rgba(0, 0, 0, 0.08), 0 0 3px #B7BDF8;
}
.composer-inner-wrap .composer-action-bar-wrap .composer-action-bar-content.unfocused {
  background-color: #363A4F;
}
.unsubscribe-action {
  color: #B7BDF8;
  text-decoration: underline;
}
.undo-redo-toast .content {
  background: #B7BDF8;
}
.preferences-wrap .container-accounts .accounts-content .account-details {
  background-color: #24273A;
}
.nylas-editable-list .items-wrapper {
  background-color: #363A4F;
}
.thread-injected-quick-actions .btn {
  box-shadow: none;
}
.thread-list .list-item .list-column-HoverActions .action.action-trash {
  background: url('../static/images/thread-list-quick-actions/ic-quick-button-trash@2x.png') center no-repeat, #B7BDF8;
}
.thread-list .list-item .list-column-HoverActions .action.action-archive {
  background: url('../static/images/thread-list-quick-actions/ic-quick-button-archive@2x.png') center no-repeat, #B7BDF8;
}
.thread-list .list-item .list-column-HoverActions .action.action-snooze {
  background: url('../static/images/thread-list-quick-actions/ic-quickaction-snooze@2x.png') center no-repeat, #B7BDF8;
}
.thread-list .thread-icon.thread-icon-star,
.draft-list .thread-icon.thread-icon-star {
  filter: grayscale(100%);
}
#message-list .mail-label.removable {
  color: #24273A !important;
  background: #B7BDF8 !important;
  box-shadow: none !important;
}
.thread-list .thread-icon.thread-icon-unread,
.draft-list .thread-icon.thread-icon-unread {
  filter: grayscale(100%);
}
.thread-icon:not(.thread-icon-unread):not(.thread-icon-star) {
  -webkit-filter: invert(100%);
}
img.content-dark {
  -webkit-filter: invert(100%);
}
img.content-light {
  -webkit-filter: invert(100%);
}
.mail-label {
  -webkit-filter: contrast(110%) brightness(85%);
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 200;
  src: url('mailspring://custom-fonts/fonts/Custom-Thin.otf');
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 300;
  src: url('mailspring://custom-fonts/fonts/Custom-Blond.otf');
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 400;
  src: url('mailspring://custom-fonts/fonts/Custom-Normal.otf');
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 500;
  src: url('mailspring://custom-fonts/fonts/Custom-Medium.otf');
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 600;
  src: url('mailspring://custom-fonts/fonts/Custom-SemiBold.otf');
}
@font-face {
  font-family: 'Nylas-Pro';
  font-style: normal;
  font-weight: 600;
  src: url('mailspring://custom-fonts/fonts/Custom-Normal.otf'), Helvetica, sans-serif;
  unicode-range: U+1f300-1f5ff, U+1f600-1f64f, U+1f680-1f6ff, U+2600-26ff;
}
.ignore-in-parent-frame html,
.ignore-in-parent-frame body {
  font-size: 14.5px;
  line-height: 1.5;
  color: #CAD3F5;
  background-color: transparent !important;
  border: 0;
  margin: 0;
  padding: 0;
  -webkit-text-size-adjust: auto;
  word-wrap: break-word;
  -webkit-nbsp-mode: space;
  -webkit-line-break: after-white-space;
}
.ignore-in-parent-frame html {
  overflow-x: auto;
  overflow-y: hidden;
}
.ignore-in-parent-frame #inbox-html-wrapper {
  font-family: 'Nylas-Pro', 'Helvetica', 'Lucidia Grande', sans-serif;
}
.ignore-in-parent-frame #inbox-html-wrapper.platform-win32 {
  font-family: system-ui;
}
.ignore-in-parent-frame #inbox-plain-wrapper {
  font-family: 'DejaVu Sans Mono', Menlo, Monaco, Consolas, 'Courier New', monospace;
  font-size: 14px;
  white-space: pre-line;
}
.ignore-in-parent-frame strong,
.ignore-in-parent-frame b,
.ignore-in-parent-frame .bold {
  font-weight: 600;
}
.ignore-in-parent-frame body {
  padding: 0;
  margin: auto;
  -webkit-font-smoothing: antialiased;
}
.ignore-in-parent-frame body.restrict-width {
  max-width: 840px;
}
.ignore-in-parent-frame a {
  word-break: break-word;
}
.ignore-in-parent-frame blockquote {
  border-left: 2px solid #eee;
  margin: 0;
  padding: 0 0 0 10px;
  -webkit-margin-after: initial !important;
  -webkit-margin-before: initial !important;
  -webkit-margin-start: initial !important;
  -webkit-margin-end: initial !important;
}
.ignore-in-parent-frame a {
  color: #B7BDF8;
}
.ignore-in-parent-frame a:hover {
  color: #F5E0DC;
}
.ignore-in-parent-frame a:visited {
  color: #8992f3;
}
.ignore-in-parent-frame a img {
  border-bottom: 0;
}
.ignore-in-parent-frame div,
.ignore-in-parent-frame pre {
  max-width: 100%;
}
.ignore-in-parent-frame p {
  margin: 0;
  padding: 0;
  margin-bottom: 0;
}
.ignore-in-parent-frame pre.nylas-plaintext {
  font-family: 'Nylas-Pro', 'Helvetica', 'Lucidia Grande', sans-serif;
  white-space: pre-wrap;
  word-wrap: break-word;
}
.ignore-in-parent-frame img {
  border: 0;
}
.ignore-in-parent-frame search-match,
.ignore-in-parent-frame .search-match {
  background: #fff000;
  border-radius: 3px;
  box-shadow: 0 0.5px 0.5px rgba(0, 0, 0, 0.25);
}
.ignore-in-parent-frame search-match.current-match,
.ignore-in-parent-frame .search-match.current-match {
  background: #ff8b1a;
}
.ignore-in-parent-frame .inline-download-prompt {
  border: solid 1px rgba(0, 0, 0, 0.09);
  border-radius: 2px;
  color: #CAD3F5;
  background: #24273A;
  margin: 4px 0;
  padding: 4px 8px;
  cursor: pointer;
  display: inline-block;
  white-space: nowrap;
  text-overflow: ellipsis;
  overflow: hidden;
}
.ignore-in-parent-frame .inline-download-prompt:hover {
  cursor: pointer;
  color: #CAD3F5;
  border: solid 1px rgba(0, 0, 0, 0.16);
}
